.darma-loader-darma-custom-501 {
   width: 70px;
   aspect-ratio: 1;
   color: var(--loader-color, #0f766e);
   background: radial-gradient(150% 150% at left -40% top -40%,#0000 98%,currentColor) left top, radial-gradient(150% 150% at right -40% top -40%,#0000 98%,currentColor) right top, radial-gradient(150% 150% at left -40% bottom -40%,#0000 98%,currentColor) left bottom, radial-gradient(150% 150% at right -40% bottom -40%,#0000 98%,currentColor) right bottom;
   background-size: 50.3% 50.3%;
   background-repeat: no-repeat;
   -webkit-mask: radial-gradient(circle 5px,#0000 90%,currentColor);
   animation: darma-loader-darma-custom-501-l7 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-501-l7  {
  100%{transform: rotate(1turn)}
}

